    if (!g_damagecooldown) {
        for (i = 0; i < MAX_ENEMIES; ++i) {
            if (!g_enemies[i].active) continue;
            if (rect_overlap((i16)g_player.x, (i16)g_player.y, g_player.w, g_player.h,
