            g_lives = 2;
            reset_player_to_checkpoint();
            g_damagecooldown = 50;
        } else {
            g_gameover = 1;
        }
    }

    if (!g_checkpointactive && g_player.x >= 44) {
        g_checkpointactive = 1;
        g_checkpointx = 44;
        g_checkpointy = 120;
    }

